// src/components/ForecastCard.jsx
import React from "react";

export default function ForecastCard() {
  const forecast = Array.from({ length: 16 }, (_, i) => ({
    day: `Day ${i + 1}`,
    temp: `${Math.floor(28 + Math.random() * 8)}°C`,
    condition: ["Sunny", "Cloudy", "Rain", "Storm"][i % 4],
  }));

  return (
    <div className="w-full px-6 mt-10 z-10">
      <h2 className="text-xl font-bold text-white mb-4 drop-shadow-glow">
        16-Day Forecast
      </h2>
      <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-8 gap-4">
        {forecast.map((day, idx) => (
          <div
            key={idx}
            className="flex flex-col items-center justify-center bg-white/10 backdrop-blur-xl rounded-xl shadow-lg p-4 text-white"
          >
            <p className="text-sm font-medium mb-1">{day.day}</p>
            <p className="text-xl font-bold text-purple-400">{day.temp}</p>
            <p className="text-xs text-white/70 mt-1">{day.condition}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
